import React from 'react';
import { motion } from 'framer-motion';

const Home = ({ lang }) => {
  const texts = {
    English: { sell: "Sell Crops", buy: "Buy Crops", voice: "Speak Now" },
    हिन्दी: { sell: "फसल बेचें", buy: "फसल खरीदें", voice: "बोलें" },
    मराठी: { sell: "पीक विका", buy: "पीक खरेदी करा", voice: "बोला" }
  };

  return (
    <div className="flex flex-col gap-6 p-6 items-center justify-center min-h-[80vh]">
      <motion.button 
        whileTap={{ scale: 0.9 }}
        className="w-full h-40 bg-green-600 rounded-3xl shadow-xl text-white text-4xl font-bold flex flex-col items-center justify-center border-b-8 border-green-800"
      >
        🚜 {texts[lang].sell}
      </motion.button>

      <motion.button 
        whileTap={{ scale: 0.9 }}
        className="w-full h-40 bg-orange-500 rounded-3xl shadow-xl text-white text-4xl font-bold flex flex-col items-center justify-center border-b-8 border-orange-700"
      >
        🛒 {texts[lang].buy}
      </motion.button>

      <div className="mt-10 flex flex-col items-center">
        <button className="w-20 h-20 bg-blue-500 rounded-full flex items-center justify-center text-3xl shadow-lg animate-pulse">
          🎤
        </button>
        <p className="mt-2 font-bold text-blue-600 uppercase tracking-widest">{texts[lang].voice}</p>
      </div>
    </div>
  );
};

export default Home;
